["customText"] = "function()\n    if WeakAuras.IsOptionsOpen() then   \n        return NSAPI:GetName(\"player\", \"GlobalNickNames\")\n    else\n        local u = aura_env.state.unit\n        if aura_env.state and u then\n            return NSAPI:GetName(u, \"GlobalNickNames\")\n        end\n    end\nend\n\n\n\n\n\n\n\n\n\n\n",
