["triggers"] = {
{
["trigger"] = {
["type"] = "custom",
["subeventSuffix"] = "_CAST_START",
["customVariables"] = "{\n    expirationTime = true,\n    class = \"string\",\n    init = \"bool\",\n}",
["event"] = "Health",
["unit"] = "player",
["custom_type"] = "stateupdate",
["subeventPrefix"] = "SPELL",
["custom"] = "function(allstates,event,...)\n    if event == \"UNIT_SPELLCAST_SUCCEEDED\" then\n        local unit = ...\n        local GUID = UnitGUID(unit)\n        if not issecretvalue(GUID) then\n            aura_env.lastInterruptee = GUID\n        end\n    elseif event == \"RG_EXTERNAL_STACK_RECHECK\" then\n        local key = ...\n        local state = key and allstates[key]\n        if state and state.expirationTime and state.expirationTime < GetTime() and state.maxStacks and state.stacks and state.stacks < state.maxStacks then\n            state.stacks = min(state.stacks + 1, state.maxStacks)\n            if state.stacks < state.maxStacks then\n                aura_env.scheduleRecheck(state.GUID, state.duration + 0.1)\n                state.expirationTime = GetTime() + state.duration\n            else\n                state.expirationTime = nil\n            end\n            state.changed = true\n            return true\n        end    \n    elseif event == \"UNIT_AURA\" then\n        local unit, updateInfo = ...\n        if not aura_env.GUIDToUnit then aura_env.GUIDToUnit = {} end\n        \n        if updateInfo and updateInfo.addedAuras then\n            for _, aura in ipairs(updateInfo.addedAuras) do \n                local isExternal = not C_UnitAuras.IsAuraFilteredOutByInstanceID(unit, aura.auraInstanceID, \"HELPFUL|EXTERNAL_DEFENSIVE\")\n                \n                if isExternal then\n                    local sourceGUID = aura_env.lastInterruptee\n                    local sourceUnit = aura_env.GUIDToUnit[sourceGUID or \"\"]\n                    local sourceSpec = sourceUnit and WeakAuras.SpecForUnit(sourceUnit)\n                    local cdDataArray = aura_env.specToExternal[sourceSpec or \"\"]\n                    local index = 1\n                    if cdDataArray and type(cdDataArray.index) == \"function\" then\n                        index = cdDataArray.index(sourceUnit, unit, aura.auraInstanceID)\n                    end\n                    local cdData = cdDataArray and cdDataArray[index or \"\"]\n                    local key = format(\"%s:%s\", sourceGUID or \"\", cdData and cdData.spell or \"\")\n                    \n                    local state = allstates[key]\n                    if state then\n                        local d\n                        if type(cdData.duration) == \"function\" then\n                            d = cdData.duration(state.unit)\n                        else\n                            d = cdData.duration\n                        end                          \n                        if state.maxStacks and state.stacks then\n                            if state.stacks == state.maxStacks then\n                                state.expirationTime = GetTime() + d\n                                aura_env.scheduleRecheck(key, d + 0.1)\n                            end\n                            state.stacks = max(state.stacks - 1, 0)                                \n                        else\n                            state.expirationTime = GetTime() + d\n                        end         \n                        state.duration = d               \n                        state.changed = true\n                        state.auraInstanceID = aura.auraInstanceID\n                        state.auraUnit = unit\n                        if cdData.customCheck then\n                            local delay\n                            if type(cdData.customCheckDelay) == \"function\" then\n                                delay = cdData.customCheckDelay(state)\n                            else\n                                delay = cdData.customCheckDelay\n                            end\n                            if delay then\n                                aura_env.scheduleCustomCheck(key, delay, cdData.customCheck, state)                                    \n                            end\n                        end\n                        return true\n                    end\n                end\n            end\n        end    \n    elseif event == \"RG_EXTERNAL_APPLY_CHANGES\" then\n        return true    \n    elseif event == \"STATUS\" or event == \"GROUP_ROSTER_UPDATE\" or event == \"ENCOUNTER_START\" or event == \"READY_CHECK\" or event == \"RG_EXTERNAL_SPEC_CHANGE\" or event == \"ADDON_RESTRICTION_STATE_CHANGED\" then\n        if event == \"ENCOUNTER_START\" then\n            aura_env.GUIDToUnit = {[\"\"] = false}\n            for unit in WA_IterateGroupMembers() do\n                local GUID = UnitGUID(unit)\n                aura_env.GUIDToUnit[GUID] = unit\n            end\n        end\n        if event == \"STATUS\" then\n            for key in pairs(aura_env.timers) do\n                aura_env.timers[key]:Cancel()\n                aura_env.timers[key] = nil\n            end\n        end\n        local foundsStates = {}\n        for unit in WA_IterateGroupMembers() do\n            local GUID = UnitGUID(unit) \n            local class = UnitClassBase(unit)\n            local spec, role, pos, talentString = WeakAuras.SpecRolePositionForUnit(unit)\n            if UnitIsVisible(unit) and GUID and class and not hasanysecretvalues(GUID, class) then\n                local cdDataArray = aura_env.specToExternal[spec or \"\"]\n                if cdDataArray then\n                    for i, cdData in ipairs(cdDataArray) do\n                        local d\n                        if type(cdData.duration) == \"function\" then\n                            d = cdData.duration(unit)\n                        else\n                            d = cdData.duration\n                        end\n                        local s\n                        if type(cdData.stacks) == \"function\" then\n                            s = cdData.stacks(unit)\n                        else\n                            s = cdData.stacks\n                        end\n                        local key = format(\"%s:%s\", GUID, cdData.spell)\n                        foundsStates[key] = true\n                        if (not allstates[key] or allstates[key].spec ~= spec or allstates[key].talentString ~= talentString) and not cdData.disabled then\n                            allstates[key] = {\n                                show = true,\n                                changed = true,    \n                                GUID = GUID,\n                                unit = unit,\n                                spec = spec,\n                                talentString = talentString,\n                                class = class,\n                                spellID = cdData.spell,\n                                icon = C_Spell.GetSpellTexture(cdData.spell),\n                                progressType = \"timed\",\n                                duration = d,\n                                maxStacks = s,\n                                stacks = s,\n                                index = cdData.spell,\n                            }\n                        elseif not cdData.disabled then\n                            allstates[key].duration = d\n                            allstates[key].maxStacks = s\n                        end\n                    end               \n                end\n            end\n        end\n        for key in pairs(allstates) do\n            if not foundsStates[key] then\n                allstates[key].show = false\n                allstates[key].changed = true\n                if aura_env.timers[key] then\n                    aura_env.timers[key]:Cancel()\n                    aura_env.timers[key] = nil\n                end\n            end\n        end\n        return true\n    elseif event == \"ENCOUNTER_END\" then\n        local name, instanceType = GetInstanceInfo()\n        if instanceType == \"raid\" then\n            for key in pairs(allstates) do\n                allstates[key].expirationTime = nil\n                allstates[key].stacks = allstates[key].maxStacks\n                allstates[key].changed = true\n                if aura_env.timers[key] then\n                    aura_env.timers[key]:Cancel()\n                    aura_env.timers[key] = nil\n                end\n            end\n            return true\n        end\n    elseif event == \"OPTIONS\" then\n        for i=1,10 do\n            local unit = \"player\"\n            local GUID = UnitGUID(unit)\n            local class = UnitClassBase(unit)\n            local spec = WeakAuras.SpecForUnit(unit)\n            local intInfo = aura_env.specToExternal[65][1]\n            if intInfo then\n                local d\n                if type(intInfo.duration) == \"function\" then\n                    d = intInfo.duration(unit)\n                else\n                    d = intInfo.duration\n                end\n                allstates[i] = {\n                    show = true,\n                    changed = true,    \n                    GUID = GUID,\n                    spec = spec,\n                    class = class,\n                    icon = C_Spell.GetSpellTexture(intInfo.spell),\n                    progressType = \"timed\",\n                    expirationTime = GetTime() + 10,\n                    duration = 10,\n                    index = intInfo.spell,\n                    stacks = 1,\n                }\n            end\n        end \n    end \nend",
