["init"] = {
["custom"] = "aura_env.specToExternal = {\n    [105] = { -- Restoration\n        {\n            spell = 102342, \n            duration = function(unit) \n                local tal = WeakAuras.CheckTalentForUnit(unit, 103139)\n                if tal and tal > 0 then\n                    return 70 \n                else\n                    return 90\n                end            \n            end,\n        }\n    },\n    [65] = { -- Holy\n        index = function(sourceUnit, targetUnit, auraInstanceID)\n            -- magic bop and physical bop are not in BIG_DEFENSIVE filter\n            local isBigDefensive = not C_UnitAuras.IsAuraFilteredOutByInstanceID(targetUnit, auraInstanceID, \"HELPFUL|BIG_DEFENSIVE\")\n            if isBigDefensive then\n                return 1\n            else \n                return 2\n            end\n        end,\n        {\n            spell = 6940, \n            duration = function(unit)\n                local sactal = WeakAuras.CheckTalentForUnit(unit, 102595)\n                if sactal and sactal > 0 then\n                    return 60\n                else \n                    return 120\n                end\n            end,\n        },\n        {\n            spell = 1022, \n            duration = function(unit)\n                local boptal = WeakAuras.CheckTalentForUnit(unit, 102606)\n                if boptal and boptal > 0 then\n                    return 240\n                else \n                    return 300\n                end\n            end,\n            disabled = aura_env.config.disableBoP,\n        },\n    }, \n    [66] = { -- Protection\n        index = function(sourceUnit, targetUnit, auraInstanceID)\n            -- magic bop and physical bop are not in BIG_DEFENSIVE filter\n            local isBigDefensive = not C_UnitAuras.IsAuraFilteredOutByInstanceID(targetUnit, auraInstanceID, \"HELPFUL|BIG_DEFENSIVE\")\n            if isBigDefensive then\n                return 1\n            else \n                return 2\n            end\n        end,\n        {\n            spell = 6940, \n            duration = function(unit)\n                local sactal = WeakAuras.CheckTalentForUnit(unit, 102595)\n                if sactal and sactal > 0 then\n                    return 60\n                else \n                    return 120\n                end\n            end,\n        },\n        {\n            spell = 1022, \n            duration = function(unit)\n                local boptal = WeakAuras.CheckTalentForUnit(unit, 102606)\n                if boptal and boptal > 0 then\n                    return 240\n                else \n                    return 300\n                end\n            end,\n            disabled = aura_env.config.disableBoP,\n        },\n    },    \n    [70] = { -- Retribution\n        index = function(sourceUnit, targetUnit, auraInstanceID)\n            -- magic bop and physical bop are not in BIG_DEFENSIVE filter\n            local isBigDefensive = not C_UnitAuras.IsAuraFilteredOutByInstanceID(targetUnit, auraInstanceID, \"HELPFUL|BIG_DEFENSIVE\")\n            if isBigDefensive then\n                return 1\n            else \n                return 2\n            end\n        end,\n        {\n            spell = 6940, \n            duration = function(unit)\n                local sactal = WeakAuras.CheckTalentForUnit(unit, 102595)\n                if sactal and sactal > 0 then\n                    return 60\n                else \n                    return 120\n                end\n            end,\n        },\n        {\n            spell = 1022, \n            duration = function(unit)\n                local boptal = WeakAuras.CheckTalentForUnit(unit, 102606)\n                if boptal and boptal > 0 then\n                    return 240\n                else \n                    return 300\n                end\n            end,\n            disabled = aura_env.config.disableBoP,\n        },\n    },\n    [256] = { -- Discipline\n        {\n            spell = 33206, \n            duration = 180,\n            stacks = function(unit)\n                local talent = WeakAuras.CheckTalentForUnit(unit, 103714)\n                if talent and talent > 0 then\n                    return 2\n                else\n                    return nil\n                end\n            end\n        }\n    }, \n    [257] = { -- Holy\n        {\n            spell = 47788, \n            duration = 180,\n            customCheckDelay = function(state)\n                local sourceUnit = state.unit\n                local cdrTal = WeakAuras.CheckTalentForUnit(sourceUnit, 128315)\n                if cdrTal and cdrTal > 0 then\n                    local durationTal = WeakAuras.CheckTalentForUnit(sourceUnit, 117292)\n                    if durationTal and durationTal > 0 then\n                        return 11.85\n                    else\n                        return 9.85\n                    end\n                end\n            end,\n            customCheck = function(state)\n                local unit = state.auraUnit\n                local auraInstanceID = state.auraInstanceID\n                -- if thi this is true most likely we're seeing not a sac\n                if UnitExists(unit) and C_UnitAuras.GetAuraDataByAuraInstanceID(unit, auraInstanceID) then        \n                    state.expirationTime = GetTime() + 60\n                    state.duration = 60\n                    state.changed = true\n                    WeakAuras.ScanEvents(\"RG_EXTERNAL_APPLY_CHANGES\")\n                end\n            end,\n        },\n    },\n    [1468] = { -- Preservation\n        {\n            spell = 357170, \n            duration = function(unit)\n                local talent = WeakAuras.CheckTalentForUnit(unit, 115648)\n                if talent and talent > 0 then\n                    return 50\n                else\n                    return 60\n                end\n            end,\n            stacks = function(unit)\n                local talent = WeakAuras.CheckTalentForUnit(unit, 115648)\n                if talent and talent > 0 then\n                    return 2\n                else\n                    return nil\n                end\n            end\n        }\n    },   \n    [270] = { -- Mistweaver\n        {\n            spell = 116849,\n            duration = 75,\n        }\n    }\n}\n\n\naura_env.timers = aura_env.timers or {}\nfunction aura_env.scheduleRecheck(key, delay)\n    if not aura_env.timers[key] then\n        aura_env.timers[key] = C_Timer.NewTimer(delay, function()\n                WeakAuras.ScanEvents(\"RG_EXTERNAL_STACK_RECHECK\", key)\n                aura_env.timers[key] = nil\n        end)\n    else\n        aura_env.timers[key]:Cancel()\n        aura_env.timers[key] = C_Timer.NewTimer(delay, function()\n                WeakAuras.ScanEvents(\"RG_EXTERNAL_STACK_RECHECK\", key)\n                aura_env.timers[key] = nil\n        end)\n    end\nend\n\naura_env.customCheckTimers = aura_env.customCheckTimers or {}\n\nlocal function run(self)\n    self.f(SafeUnpack(self.args))\n    aura_env.customCheckTimers[self.key] = nil\nend\nfunction aura_env.scheduleCustomCheck(key, delay, func, ...)\n    if not aura_env.customCheckTimers[key] then\n        aura_env.customCheckTimers[key] = C_Timer.NewTimer(delay, run)\n    else\n        aura_env.customCheckTimers[key]:Cancel()\n        aura_env.customCheckTimers[key] = C_Timer.NewTimer(delay, run)\n    end\n    aura_env.customCheckTimers[key].f = func\n    aura_env.customCheckTimers[key].args = SafePack(...)\n    aura_env.customCheckTimers[key].key = key\nend\n\nif not aura_env.region.LIB_SPEC_HOOK_REGISTERED then\n    local LS = LibStub(\"LibSpecialization\", true)\n    if LS then\n        local function libSpecCallback(...)\n            WeakAuras.ScanEvents(\"RG_EXTERNAL_SPEC_CHANGE\", ...)\n        end\n        LS.RegisterGroup({}, libSpecCallback)                \n        aura_env.region.LIB_SPEC_HOOK_REGISTERED = true\n    end\nend",
