["triggers"] = {
{
["trigger"] = {
["type"] = "custom",
["subeventSuffix"] = "_CAST_START",
["debuffType"] = "HELPFUL",
["event"] = "Health",
["subeventPrefix"] = "SPELL",
["names"] = {
},
["custom"] = "function(s, e, ...)\n    if e == \"OPTIONS\" then\n        for i=1, 3 do\n            local boss = \"boss\"..i\n            local state = {\n                progressType = \"timed\",\n                duration = 6,\n                expirationTime = 6+GetTime(),\n                icon = i <= 2 and C_Spell.GetSpellInfo(aura_env.TauntIcons[1]).iconID or 237552,\n                text = NSAPI:Shorten(\"player\", 8, true, \"GlobalNickNames\", true),\n                isTarget = i >= 2,\n                autoHide = true,\n            }\n            s:Update(boss, state)\n        end\n    elseif e == \"ENCOUNTER_START\" then\n        aura_env.tanking = {}\n        for i=1, 10 do\n            if UnitExists(\"boss\"..i) then\n                aura_env.tanking[\"boss\"..i] = false\n            end\n        end        \n    elseif e == \"ENCOUNTER_END\" then\n        aura_env.tanking = {}\n    elseif e == \"UNIT_THREAT_SITUATION_UPDATE\" then\n        local unit = ...\n        if UnitGroupRolesAssigned(unit) == \"TANK\" then\n            for i=1, 10 do -- iterate all bosses\n                local boss = \"boss\"..i\n                if UnitExists(boss) then\n                    local threatLevel = UnitThreatSituation(\"player\", boss)\n                    local isTanking = threatLevel and threatLevel >= 2\n                    if aura_env.tanking[boss] and not isTanking then \n                        -- if player was previously tanking the boss but isn't anymore\n                        local TankThreat = false\n                        local ThreatUnit = nil\n                        for u in WA_IterateGroupMembers() do\n                            local unitThreatLevel = UnitThreatSituation(u, boss) \n                            local HasThreat = unitThreatLevel and unitThreatLevel >= 2\n                            if HasThreat then\n                                ThreatUnit = u\n                                TankThreat = UnitGroupRolesAssigned(u) == \"TANK\"\n                                break\n                            end\n                        end                        \n                        \n                        local state = {\n                            progressType = \"timed\",\n                            duration = 6,\n                            expirationTime = 6+GetTime(),\n                            icon = TankThreat and C_Spell.GetSpellInfo(aura_env.TauntIcons[select(3, UnitClass(ThreatUnit))]).iconID or 237552,\n                            isTarget = UnitIsUnit(boss, \"target\"),                            \n                            text = NSAPI:Shorten(ThreatUnit, 8, true, \"GlobalNickNames\", true),\n                            TankThreat = TankThreat,\n                            autoHide = true,\n                        }\n                        s:Update(boss, state)\n                        aura_env.tanking[boss] = isTanking\n                        break\n                    end\n                    aura_env.tanking[boss] = isTanking\n                end\n            end\n        end\n    end\nend\n\n\n",
