["custom"] = "function(s, e, ...)\n    if e == \"OPTIONS\" then        \n        local state = {\n            show = true,\n            progressType = \"timed\",\n            duration = 9,\n            unit = \"player\",\n            expirationTime = 9+GetTime(),\n            text = \"Dispel:\",\n            name = NSAPI and NSAPI:Shorten(\"player\", 8, true, \"GlobalNickNames\", true) or UnitName(\"player\"),\n            autoHide = true,\n        }\n        s:Update(\"player\"..1, state)\n    elseif e == \"ENCOUNTER_START\" then\n        aura_env.healers = {}\n        for unit in WA_IterateGroupMembers() do\n            if UnitGroupRolesAssigned(unit) == \"HEALER\" then\n                table.insert(aura_env.healers, unit) \n            end\n        end\n        for unit in WA_IterateGroupMembers() do\n            local class = select(3, UnitClass(unit))\n            if class == 9 then\n                table.insert(aura_env.healers, unit) \n            end\n        end\n        -- insert healers before warlocks to give them prio\n    elseif e == \"ENCOUNTER_END\" then\n        s:RemoveAll()\n    elseif e == \"UNIT_AURA\" then\n        local unit, updateInfo = ...   \n        if updateInfo.isFullUpdate and next(s) then\n            local auraInstanceIds = C_UnitAuras.GetUnitAuraInstanceIDs(unit, \"HARMFUL\")\n            local foundStates = {}\n            for i, auraInstanceID in ipairs(auraInstanceIds) do\n                if s[unit..auraInstanceID] then\n                    foundStates[unit..auraInstanceID] = true \n                end \n            end\n            \n            for k, v in pairs(s) do\n                if not foundStates[k] then\n                    s:Remove(k) \n                end \n            end\n        end\n        \n        if updateInfo.addedAuras then\n            for i, auraData in ipairs(updateInfo.addedAuras) do                \n                local auraInstanceID = auraData.auraInstanceID\n                local isDebuff = not C_UnitAuras.IsAuraFilteredOutByInstanceID(unit, auraInstanceID, \"HARMFUL\")\n                if isDebuff then\n                    if auraData.dispelName ~= nil then   \n                        local now = GetTime()\n                        if not aura_env.last or aura_env.last < now-3 then\n                            aura_env.last = now\n                            aura_env.affected = {}\n                            local aura_env = aura_env\n                            C_Timer.After(0.2, function()\n                                    M33kAuras.ScanEvents(\"NS_ASSIGN_EVENT\", aura_env.id)\n                            end)\n                        end\n                        local race = select(3, UnitRace(unit))\n                        local isdwarf = race == 3 or race == 34\n                        local index = UnitInRaid(unit)\n                        table.insert(aura_env.affected, {unit, index, auraInstanceID, false, isdwarf and 1 or 0})\n                    end\n                end\n            end\n        end\n        if updateInfo.removedAuraInstanceIDs then\n            for i, auraInstanceID in ipairs(updateInfo.removedAuraInstanceIDs)  do\n                if s[unit..auraInstanceID]  then                    \n                    s:Remove(unit..auraInstanceID)\n                end\n            end\n        end\n    elseif e == \"NS_ASSIGN_EVENT\" and aura_env.id == ... then\n        if #aura_env.affected > 15 then return end -- don't assign on mass apply as you revival those\n        table.sort(aura_env.affected, \n            function(a, b)\n                if a[5] == b[5] then\n                    return a[2] < b[2]\n                else\n                    return a[5] < b[5]\n                end\n        end)\n        local now = GetTime()\n        aura_env.last = nil\n        aura_env.healerassigned = {}\n        for i, v in ipairs(aura_env.healers or {}) do\n            if not UnitIsDead(v) then\n                for k, info in ipairs(aura_env.affected) do\n                    if UnitIsUnit(info[1], v) then\n                        info[4] = true\n                        aura_env.healerassigned[i] = true\n                        if UnitIsUnit(v, \"player\") then\n                            local state = {\n                                show = true,\n                                progressType = \"timed\",\n                                duration = 9,\n                                unit = info[1],\n                                expirationTime = 9+GetTime(),\n                                text = \"Dispel:\",\n                                name = NSAPI and NSAPI:Shorten(info[1], 8, true, \"GlobalNickNames\", true) or UnitName(info[1]),\n                                autoHide = true,\n                            }\n                            s:Update(info[1]..info[3], state)\n                        end\n                        break \n                    end\n                end \n            end\n        end\n        \n        for i, v in ipairs(aura_env.healers or {}) do\n            if (not UnitIsDead(v)) and not aura_env.healerassigned[i] then\n                for k, info in ipairs(aura_env.affected) do\n                    if not info[4] then\n                        info[4] = true\n                        aura_env.healerassigned[i] = true\n                        if UnitIsUnit(v, \"player\") then\n                            local state = {\n                                show = true,\n                                progressType = \"timed\",\n                                duration = 9,\n                                unit = info[1],\n                                expirationTime = 9+GetTime(),\n                                text = \"Dispel:\",\n                                name = NSAPI and NSAPI:Shorten(info[1], 8, true, \"GlobalNickNames\", true) or UnitName(info[1]),\n                                autoHide = true,\n                            }\n                            s:Update(info[1]..info[3], state)\n                        end\n                        break \n                    end\n                end \n            end\n        end\n        \n        for i, info in ipairs(aura_env.affected) do\n            if UnitIsUnit(info[1], \"player\") and not info[4] then\n                if info[5] == 1 then\n                    M33kAuras.ScanEvents(\"NS_SELF_DWARF\", aura_env.id) \n                end\n            end\n        end\n    end\nend\n\n\n\n",
