["triggers"] = {
{
["trigger"] = {
["type"] = "custom",
["subeventSuffix"] = "_CAST_START",
["event"] = "Health",
["subeventPrefix"] = "SPELL",
["unit"] = "player",
["spellIds"] = {
},
["events"] = "UNIT_AURA:nameplate UNIT_DIED ENCOUNTER_START NAME_PLATE_UNIT_REMOVED ENCOUNTER_TIMELINE_EVENT_ADDED ENCOUNTER_END",
["custom_type"] = "stateupdate",
["check"] = "event",
["names"] = {
},
["custom"] = "function(s, e, ...)\n    if e == \"UNIT_DIED\" and aura_env.phase == 1 then\n        local G = ...\n        if not issecretvalue(G) then return end -- if GUID isn't secret, it's a friendly target dying\n        local now = GetTime()\n        aura_env.AllowedTime[now+3.5] = true\n        local aura_env = aura_env\n        C_Timer.After(4, function()\n                aura_env.AllowedTime[now+3.5] = nil    \n        end)\n        \n        \n    elseif e == \"ENCOUNTER_START\" then\n        aura_env.StartTime = GetTime()\n        aura_env.AllowedTime = {}\n        aura_env.PossibleID = {}\n        aura_env.timelines = {}\n        aura_env.count = {}\n        aura_env.data = {}\n        aura_env.completed = {}\n        aura_env.phase = 1\n    elseif e == \"ENCOUNTER_END\" then\n        s:RemoveAll()\n    elseif e == \"ENCOUNTER_TIMELINE_EVENT_ADDED\" and aura_env.phase == 1 then\n        local info = ...\n        local now = GetTime()\n        if now - aura_env.StartTime < 5 then return end\n        aura_env.timelines = aura_env.timelines or {}\n        if info.duration == 1.5 or info.duration == 6 or info.duration == 25 then\n            table.insert(aura_env.timelines, now)\n            local count = 0\n            for k, v in ipairs(aura_env.timelines) do\n                if now < v+0.1 and aura_env.phase == 1 then\n                    count = count + 1\n                    if count >= 2 then\n                        aura_env.phase = 2\n                        s:RemoveAll()\n                        return\n                    end\n                end\n            end\n        end\n    elseif e == \"NAMEPLATE_UNIT_REMOVED\" and aura_env.phase == 1 then\n        local unit = ...\n        aura_env.count[unit] = {}\n        aura_env.completed[unit] = false\n        if aura_env.data[unit] then\n            for k, v in pairs(aura_env.data[unit]) do\n                if s[unit..v] then\n                    s:Remove(unit..v)\n                end\n            end\n            aura_env.data[unit] = nil\n        end\n        \n    elseif e == \"UNIT_AURA\" and aura_env.phase == 1 then\n        local unit, updateInfo = ...    \n        local lvl = UnitLevel(unit)\n        if lvl ~= 92 then return end\n        if not aura_env.PossibleID[unit] then aura_env.PossibleID[unit] = {} end\n        \n        if updateInfo.isFullUpdate and next(s) then\n            local auraInstanceIds = C_UnitAuras.GetUnitAuraInstanceIDs(unit, \"HARMFUL\")\n            local foundStates = {}\n            for i, auraInstanceID in ipairs(auraInstanceIds) do\n                if s[unit..auraInstanceID] then\n                    foundStates[unit..auraInstanceID] = true \n                end \n            end\n            \n            for k, v in pairs(s) do\n                if not foundStates[k] then\n                    s:Remove(k) \n                end \n            end\n        end\n        \n        local allowed = false\n        local now = GetTime()\n        for time, _ in pairs(aura_env.AllowedTime) do\n            local diff = now-time\n            if diff <= 0.2 and diff >= -0.2 then\n                allowed = true\n                break\n            end\n        end\n        \n        if updateInfo.addedAuras then\n            for i, auraData in ipairs(updateInfo.addedAuras) do                \n                local auraInstanceID = auraData.auraInstanceID\n                local isDebuff = not C_UnitAuras.IsAuraFilteredOutByInstanceID(unit, auraInstanceID, \"HARMFUL\")\n                if not allowed then\n                    aura_env.PossibleID[unit..auraInstanceID] = false\n                end\n                local possible = aura_env.PossibleID[unit..auraInstanceID]\n                local completed = aura_env.completed[unit]\n                if isDebuff and auraData.dispelName ~= nil and (possible or possible == nil) and ((completed and completed == auraInstanceID) or not completed) and auraData.applications ~= nil then\n                    aura_env.PossibleID[unit..auraInstanceID] = true\n                    local duration = C_UnitAuras.GetAuraDuration(unit, auraInstanceID)\n                    if duration then   \n                        aura_env.count[unit] = aura_env.count[unit] or {}\n                        aura_env.count[unit][auraInstanceID] = 1\n                        aura_env.data[unit] = aura_env.data[unit] or {}\n                        local data = {\n                            progressType = \"durationObject\",\n                            duration = duration:GetTotalDuration(),\n                            expirationTime = duration:GetEndTime(),\n                            durationObject = duration,\n                            unit = unit,\n                            icon = auraData.icon,\n                            stacks = auraData.applications ~= nil and auraData.applications,\n                            autoHide = true,\n                        }\n                        tInsertUnique(aura_env.data[unit], auraInstanceID)\n                        s:Update(unit..auraInstanceID, data)\n                    end\n                end\n            end\n        end \n        if updateInfo.updatedAuraInstanceIDs then\n            for i, auraInstanceID in ipairs(updateInfo.updatedAuraInstanceIDs) do                          \n                local auraData = C_UnitAuras.GetAuraDataByAuraInstanceID(unit, auraInstanceID)\n                local isDebuff = not C_UnitAuras.IsAuraFilteredOutByInstanceID(unit, auraInstanceID, \"HARMFUL\")\n                if not allowed then\n                    aura_env.PossibleID[unit..auraInstanceID] = false\n                    if s[unit..auraInstanceID] then\n                        s:Remove(unit..auraInstanceID)\n                    end\n                end\n                local possible = aura_env.PossibleID[unit..auraInstanceID]\n                local completed = aura_env.completed[unit]\n                if auraData and isDebuff and auraData.dispelName ~= nil and (possible or possible == nil) and ((completed and completed == auraInstanceID) or not completed) and auraData.applications ~= nil then\n                    aura_env.PossibleID[unit..auraInstanceID] = true\n                    local duration = C_UnitAuras.GetAuraDuration(unit, auraInstanceID)\n                    if duration then   \n                        aura_env.count[unit] = aura_env.count[unit] or {}\n                        aura_env.count[unit][auraInstanceID] = aura_env.count[unit][auraInstanceID] and aura_env.count[unit][auraInstanceID]+1 or 1\n                        if aura_env.count[unit][auraInstanceID] >= 5 then\n                            aura_env.completed[unit] = auraInstanceID\n                            s:RemoveAll()\n                        end\n                        local data = {\n                            progressType = \"durationObject\",\n                            duration = duration:GetTotalDuration(),\n                            expirationTime = duration:GetEndTime(),\n                            durationObject = duration,\n                            unit = unit,\n                            icon = auraData.icon,\n                            stacks = auraData.applications ~= nil and auraData.applications,\n                            autoHide = true,\n                        }\n                        aura_env.data[unit] = aura_env.data[unit] or {}\n                        tInsertUnique(aura_env.data[unit], auraInstanceID)\n                        s:Update(unit..auraInstanceID, data)\n                    end\n                end\n            end\n        end\n        \n        \n        if updateInfo.removedAuraInstanceIDs then\n            for i, auraInstanceID in ipairs(updateInfo.removedAuraInstanceIDs)  do\n                if s[unit..auraInstanceID]  then                    \n                    s:Remove(unit..auraInstanceID)\n                end\n            end\n        end\n    elseif e == \"OPTIONS\" then\n        for i=1,3 do\n            local duration = C_DurationUtil.CreateDuration()\n            duration:SetTimeFromStart(GetTime(), 5)\n            s:Update(i, {\n                    progressType = \"durationObject\",\n                    duration = duration:GetTotalDuration(),\n                    expirationTime = duration:GetEndTime(),\n                    durationObject = duration,\n                    icon = C_Spell.GetSpellTexture(1261531),\n                    unit = \"player\",\n                    autoHide = true,\n                    stacks = 3,\n            }) \n        end\n    end\nend",
