["event"] = "Chat Message",
["unit"] = "player",
["events"] = "ENCOUNTER_START ENCOUNTER_END UNIT_SPELLCAST_START:boss RELOE_RESET_INTERRUPUTS UNIT_SPELLCAST_STOP:boss UNIT_DIED",
["custom"] = "function(s, e, ...)\n    if e == \"OPTIONS\" then        \n        s[\"\"] = {\n            show = true,\n            icon = 1, -- iconnumber\n            glow = false, -- glow because you are next\n            next = true,\n            dead = UnitIsDeadOrGhost(\"player\"),            \n            num = 1, -- Interrupt number\n            name = UnitName(\"player\"), -- Name of next Interrupt\n            assigned = true, -- If you are assigned to this npc at all\n            changed = true,\n            progressType = \"static\",\n            autoHide = false,\n        } \n        return true        \n    elseif e == \"UNIT_DIED\" then\n        local G = ...\n        if issecretvalue(G) and UnitExists(\"boss2\") and UnitIsEnemy(\"boss2\", \"player\") then \n            if aura_env.myTrackedID == 4 then \n                aura_env.myTrackedID = 3\n            elseif aura_env.myTrackedID == 3 then\n                if not (UnitExists(\"boss3\")) then\n                    aura_env.myTrackedID = 2\n                end\n            end\n            return\n        end\n        if not UnitExists(\"boss2\") then\n            M33kAuras.ScanEvents(\"RELOE_RESET_INTERRUPUTS\")\n        end\n    elseif e == \"ENCOUNTER_START\" then\n        local pers, shared = NSAPI:GetReminderString()\n        if not pers then pers = \"\" end\n        if not shared then shared = \"\" end\n        local MRT = C_AddOns.IsAddOnLoaded(\"MRT\") and _G.VMRT.Note.Text1 or \"\"\n        local str = shared..pers..MRT\n        local count = 1\n        aura_env.assigns = {}\n        aura_env.last = GetTime()\n        aura_env.myID = 0\n        aura_env.myKick = 0\n        aura_env.castcount = 0\n        for line in string.gmatch(str,'[^\\r\\n]+') do\n            line = strtrim(line)\n            if strlower(line) == \"intend\" then\n                aura_env.assign = false\n                aura_env.myTrackedID = aura_env.myID\n                return true\n            elseif strlower(line) == \"intstart\" then\n                aura_env.assign = true\n            elseif aura_env.assign then\n                local num = 0\n                count = count+1\n                aura_env.assigns[count] = aura_env.assigns[count] or {}\n                for name in line:gmatch(\"%S+\") do\n                    if UnitInRaid(name) then\n                        num = num+1\n                        table.insert(aura_env.assigns[count], name)\n                        if UnitIsUnit(name, \"player\") then\n                            aura_env.myID = count\n                            aura_env.myKick = num\n                        end\n                    end\n                end\n            end\n        end\n    elseif e == \"ENCOUNTER_END\" then\n        s:RemoveAll()\n    elseif e == \"RELOE_RESET_INTERRUPUTS\" then\n        aura_env.castcount = 0\n        aura_env.myTrackedID = aura_env.myID\n        s:RemoveAll()\n        if aura_env.resettimer then\n            aura_env.resettimer:Cancel()\n            aura_env.resettimer = nil\n        end\n    elseif e == \"UNIT_SPELLCAST_START\" then\n        local unit = ...\n        if aura_env.myTrackedID and unit == \"boss\"..aura_env.myTrackedID and UnitIsEnemy(unit, \"player\") then\n            aura_env.castcount = aura_env.castcount >= 1 and aura_env.castcount or 1\n            local mykick = false\n            local nextkick = false\n            if aura_env.castcount == aura_env.myKick then\n                mykick = true\n                M33kAuras.ScanEvents(\"RELOE_INTERRUPT_SOUND\")\n            elseif aura_env.castcount+1 == aura_env.myKick then\n                nextkick = true\n            end\n            local name = aura_env.assigns and aura_env.assigns[aura_env.myID] and aura_env.assigns[aura_env.myID][aura_env.castcount] or \"\"\n            local state = {\n                show = true,\n                changed = true,\n                glow = mykick,\n                next = nextkick,\n                num = aura_env.castcount,\n                assigned = true,\n                name = name,\n                progresType = \"static\",\n            }\n            if aura_env.castcount <= aura_env.myKick then\n                s:Update(\"\", state)\n            else\n                s:RemoveAll()\n            end\n            if aura_env.castcount == 5 then -- last interrupt\n                C_Timer.After(2, function()\n                        M33kAuras.ScanEvents(\"RELOE_RESET_INTERRUPUTS\")\n                end)\n            end\n            local aura_env = aura_env\n            if aura_env.resettimer then aura_env.resettimer:Cancel() end\n            aura_env.resettimer = C_Timer.NewTimer(30, function()\n                    M33kAuras.ScanEvents(\"RELOE_RESET_INTERRUPUTS\")\n            end)\n        end\n    elseif e == \"UNIT_SPELLCAST_STOP\" then\n        local unit = ...\n        if unit == \"boss\"..aura_env.myTrackedID and UnitIsEnemy(unit, \"player\") then\n            aura_env.castcount = aura_env.castcount+1\n            local mykick = false\n            local nextkick = false\n            if aura_env.castcount == aura_env.myKick then\n                nextkick = true\n            end\n            local name = aura_env.assigns and aura_env.assigns[aura_env.myID] and aura_env.assigns[aura_env.myID][aura_env.castcount] or \"\"\n            local state = {\n                show = true,\n                changed = true,\n                glow = false,\n                next = nextkick,\n                num = aura_env.castcount,\n                assigned = true,\n                name = name,\n                progresType = \"static\",\n            }\n            if aura_env.castcount <= aura_env.myKick then\n                s:Update(\"\", state)\n            else\n                s:RemoveAll()\n            end\n            if aura_env.castcount == 5 then -- last interrupt\n                C_Timer.After(2, function()\n                        M33kAuras.ScanEvents(\"RELOE_RESET_INTERRUPUTS\")\n                end)\n            end\n            local aura_env = aura_env\n            if aura_env.resettimer then aura_env.resettimer:Cancel() end\n            aura_env.resettimer = C_Timer.NewTimer(30, function()\n                    M33kAuras.ScanEvents(\"RELOE_RESET_INTERRUPUTS\")\n            end)\n        end\n        \n    end\nend\n\n\n\n\n\n",
